            "code": "{\n  \"name\": \"telemetry-pulsar\",\n  \"source\": \"PULSAR\",\n  \"source_type\": {\n    \"Pulsar\": {\n      \"service_url\": \"pulsar://127.0.0.1:6650\",\n      \"producer_name\": \"velamq-rs\",\n      \"token\": \"\"\n    }\n  }\n}"
