            "type": "code",
            "language": "json",
            "code": "{\n  \"id\": \"act-sqlite\",\n  \"action_type\": \"SAVE_POSTGRESQL\",\n  \"source_name\": \"edge-sqlite\",\n  \"sql\": \"INSERT INTO mqtt_events(client_id, topic, payload, created_at_ms) VALUES (${client_id}, ${topic}, ${payload}, ${timestamp})\"\n}"
